package ly.com.tahaben.flavorizr.processor.android

import ly.com.tahaben.flavorizr.model.FlavorConfig
import ly.com.tahaben.flavorizr.processor.AbstractProcessor
import java.io.File

/**
 * Replaces the hardcoded android:label in AndroidManifest.xml with @string/app_name
 * so that per-flavor app names work via resValues.
 *
 * Also injects android:roundIcon="@mipmap/ic_launcher_round" when any flavor configures
 * a round icon but the manifest is missing the attribute — otherwise the per-flavor
 * round icon PNGs generated by [AndroidIconProcessor] would never be picked up.
 */
class AndroidManifestProcessor : AbstractProcessor() {
    override val name = "android:manifest"

    override fun execute(config: FlavorConfig, projectDir: File) {
        val manifestFile = File(projectDir, "src/main/AndroidManifest.xml")
        if (!manifestFile.exists()) {
            // Try the android/app path for Flutter-style projects
            val altManifest = File(projectDir, "src/androidMain/AndroidManifest.xml")
            if (altManifest.exists()) {
                processManifest(altManifest, projectDir, config)
                return
            }
            log("AndroidManifest.xml not found, skipping")
            return
        }
        processManifest(manifestFile, projectDir, config)
    }

    private fun processManifest(manifestFile: File, projectDir: File, config: FlavorConfig) {
        var content = manifestFile.readText()
        val original = content

        content = rewriteLabel(content)
        content = injectRoundIconIfNeeded(content, config)

        if (content == original) return

        manifestFile.writeText(content)
        log("Modified: ${manifestFile.relativeTo(projectDir)}")
    }

    private fun rewriteLabel(content: String): String {
        val labelPattern = Regex("""android:label\s*=\s*"[^"]*"""")
        if (!labelPattern.containsMatchIn(content)) {
            log("No android:label found in manifest, skipping label rewrite")
            return content
        }
        if (content.contains("""android:label="@string/app_name"""")) {
            log("android:label already set to @string/app_name")
            return content
        }
        return labelPattern.replaceFirst(content, """android:label="@string/app_name"""")
    }

    private fun injectRoundIconIfNeeded(content: String, config: FlavorConfig): String {
        if (!hasAnyRoundIcon(config)) return content
        if (Regex("""android:roundIcon\s*=""").containsMatchIn(content)) return content

        val iconAttrPattern = Regex("""(^[ \t]*)?(android:icon\s*=\s*"[^"]*")""", RegexOption.MULTILINE)
        val match = iconAttrPattern.find(content)
        if (match == null) {
            log("Round icon configured but android:icon attribute not found in manifest — skipping roundIcon injection")
            return content
        }
        val indent = match.groupValues[1].ifEmpty { " " }
        val iconAttr = match.groupValues[2]
        val replacement = if (match.groupValues[1].isEmpty()) {
            // android:icon was inline with another attribute — append on the same line
            """$iconAttr android:roundIcon="@mipmap/ic_launcher_round""""
        } else {
            // android:icon was on its own line — add a new line with matching indentation
            "$iconAttr\n${indent}android:roundIcon=\"@mipmap/ic_launcher_round\""
        }
        log("Injected android:roundIcon=\"@mipmap/ic_launcher_round\" into manifest")
        return content.replaceFirst(match.value, replacement)
    }

    private fun hasAnyRoundIcon(config: FlavorConfig): Boolean {
        return config.androidFlavors.values.any { flavor ->
            flavor.android?.roundIcon != null
        }
    }
}
